import React, { useState, useEffect, useRef } from 'react';
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

// ΓöÇΓöÇ CARD 1: Diagnostic Shuffler ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const SHUFFLER_ITEMS = [
    { label: 'Goose AttackOrchestrator', tag: 'AGENT', color: 'var(--plasma)' },
    { label: 'Tree-of-Thought Refinement', tag: 'ACTIVE', color: '#00FF96' },
    { label: 'Attack Taxonomy Loader', tag: 'RUNNING', color: '#FFB627' },
];

function DiagnosticShuffler() {
    const [items, setItems] = useState(SHUFFLER_ITEMS);

    useEffect(() => {
        const id = setInterval(() => {
            setItems(prev => {
                const next = [...prev];
                next.unshift(next.pop());
                return next;
            });
        }, 3000);
        return () => clearInterval(id);
    }, []);

    return (
        <div className="card-surface p-6 flex flex-col gap-4 h-full min-h-[260px]">
            <p className="font-mono text-xs tracking-widest uppercase" style={{ color: 'var(--plasma)' }}>01 ΓÇö Agentic Orchestration</p>
            <h3 className="font-sans font-bold text-lg" style={{ color: 'var(--ghost)' }}>Attack Orchestrator</h3>
            <p className="text-sm mb-2" style={{ color: 'rgba(240,239,244,0.55)' }}>Goose-driven agentic loop with tree-of-thought prompt refinement across 4 attack classes.</p>
            <div className="flex flex-col gap-2 mt-auto">
                {items.map((item, i) => (
                    <div
                        key={item.label}
                        className="flex items-center justify-between px-3 py-2 rounded-xl"
                        style={{
                            background: i === 0 ? 'rgba(123,97,255,0.12)' : 'rgba(255,255,255,0.03)',
                            border: `1px solid ${i === 0 ? 'rgba(123,97,255,0.3)' : 'rgba(255,255,255,0.06)'}`,
                            transition: 'all 0.6s cubic-bezier(0.34, 1.56, 0.64, 1)',
                            transform: i === 0 ? 'scale(1.02)' : 'scale(1)',
                        }}
                    >
                        <span className="font-sans text-xs font-medium" style={{ color: 'var(--ghost)' }}>{item.label}</span>
                        <span className="font-mono text-[10px] px-2 py-0.5 rounded" style={{ background: 'rgba(0,0,0,0.4)', color: item.color }}>{item.tag}</span>
                    </div>
                ))}
            </div>
        </div>
    );
}

// ΓöÇΓöÇ CARD 2: Telemetry Typewriter ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const FEED_MESSAGES = [
    'Γá╕ Loading medical ground truth corpus...',
    'Γ£ô  DeBERTa-v3-NLI loaded (247MB)',
    'ΓÜá  HALLUCINATION detected ΓÇö drug interaction claim',
    'ΓåÆ  Flagged span: "metformin + alcohol synergism"',
    'Γ£ô  Jailbreak resistance: 96.2% PASS',
    'Γá╣  Running BiasAuditor ΓÇö 12 demographic pairs...',
    'ΓÜá  BIAS: gender disparity score 0.34 > threshold 0.15',
    'Γ£ô  Report saved ΓåÆ ./reports/safety_2026-03-07.json',
];

function TelemetryTypewriter() {
    const [displayedText, setDisplayedText] = useState('');
    const [msgIdx, setMsgIdx] = useState(0);
    const [charIdx, setCharIdx] = useState(0);

    useEffect(() => {
        const msg = FEED_MESSAGES[msgIdx];
        if (charIdx < msg.length) {
            const id = setTimeout(() => {
                setDisplayedText(msg.slice(0, charIdx + 1));
                setCharIdx(c => c + 1);
            }, 30);
            return () => clearTimeout(id);
        } else {
            const id = setTimeout(() => {
                setMsgIdx(i => (i + 1) % FEED_MESSAGES.length);
                setCharIdx(0);
                setDisplayedText('');
            }, 1400);
            return () => clearTimeout(id);
        }
    }, [charIdx, msgIdx]);

    const getColor = (text) => {
        if (text.startsWith('ΓÜá')) return '#FFB627';
        if (text.startsWith('Γ£ô')) return '#00FF96';
        if (text.startsWith('ΓåÆ')) return 'rgba(240,239,244,0.5)';
        return 'rgba(240,239,244,0.75)';
    };

    return (
        <div className="card-surface p-6 flex flex-col gap-4 h-full min-h-[260px]">
            <p className="font-mono text-xs tracking-widest uppercase" style={{ color: 'var(--plasma)' }}>02 ΓÇö Clinical Safety Scoring</p>
            <h3 className="font-sans font-bold text-lg" style={{ color: 'var(--ghost)' }}>Live Safety Feed</h3>
            <div className="flex items-center gap-2 mb-2">
                <span className="status-dot" style={{ background: '#00FF96', boxShadow: '0 0 8px #00FF96' }} />
                <span className="font-mono text-xs" style={{ color: '#00FF96' }}>LIVE FEED</span>
            </div>
            <div
                className="flex-1 rounded-xl p-4 font-mono text-xs leading-relaxed"
                style={{ background: 'rgba(0,0,0,0.4)', border: '1px solid rgba(255,255,255,0.06)', minHeight: '120px' }}
            >
                <span style={{ color: getColor(displayedText) }}>{displayedText}</span>
                <span className="cursor-blink inline-block w-1.5 h-3.5 ml-px align-middle" style={{ background: 'var(--plasma)' }} />
            </div>
        </div>
    );
}

// ΓöÇΓöÇ CARD 3: Cursor Protocol Scheduler ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const DAYS = ['S', 'M', 'T', 'W', 'T', 'F', 'S'];

function CursorScheduler() {
    const [activeDay, setActiveDay] = useState(null);
    const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
    const [phase, setPhase] = useState('idle'); // idle | moving | clicking | saved

    useEffect(() => {
        let t;
        const sequence = async () => {
            setPhase('idle');
            await new Promise(r => { t = setTimeout(r, 1000); });
            const targetDay = 3; // Wednesday
            setPhase('moving');
            await new Promise(r => { t = setTimeout(r, 800); });
            setActiveDay(targetDay);
            setPhase('clicking');
            await new Promise(r => { t = setTimeout(r, 600); });
            setPhase('saved');
            await new Promise(r => { t = setTimeout(r, 2000); });
            setActiveDay(null);
            setPhase('idle');
        };
        const loop = setInterval(() => sequence(), 5000);
        sequence();
        return () => { clearInterval(loop); clearTimeout(t); };
    }, []);

    return (
        <div className="card-surface p-6 flex flex-col gap-4 h-full min-h-[260px]">
            <p className="font-mono text-xs tracking-widest uppercase" style={{ color: 'var(--plasma)' }}>03 ΓÇö CI/CD Safety Gate</p>
            <h3 className="font-sans font-bold text-lg" style={{ color: 'var(--ghost)' }}>Scan Scheduler</h3>
            <p className="text-sm" style={{ color: 'rgba(240,239,244,0.55)' }}>pytest plugin + GitHub Actions template. Auto-blocks unsafe deployments.</p>
            <div className="mt-auto">
                <div className="flex gap-2 mb-3">
                    {DAYS.map((d, i) => (
                        <div
                            key={i}
                            className="flex-1 aspect-square flex items-center justify-center rounded-lg font-mono text-xs font-bold cursor-default select-none"
                            style={{
                                background: activeDay === i ? 'var(--plasma)' : 'rgba(255,255,255,0.04)',
                                border: `1px solid ${activeDay === i ? 'var(--plasma)' : 'rgba(255,255,255,0.08)'}`,
                                color: activeDay === i ? '#fff' : 'rgba(240,239,244,0.4)',
                                transform: activeDay === i && phase === 'clicking' ? 'scale(0.92)' : 'scale(1)',
                                transition: 'all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1)',
                                boxShadow: activeDay === i ? '0 0 16px rgba(123,97,255,0.5)' : 'none',
                            }}
                        >
                            {d}
                        </div>
                    ))}
                </div>
                <div
                    className="w-full py-2 text-center rounded-xl font-mono text-xs font-semibold"
                    style={{
                        background: phase === 'saved' ? 'rgba(0,255,150,0.12)' : 'rgba(123,97,255,0.08)',
                        border: `1px solid ${phase === 'saved' ? 'rgba(0,255,150,0.3)' : 'rgba(123,97,255,0.2)'}`,
                        color: phase === 'saved' ? '#00FF96' : 'rgba(240,239,244,0.5)',
                        transition: 'all 0.4s ease',
                    }}
                >
                    {phase === 'saved' ? 'Γ£ô Schedule Saved ΓÇö CI Gate Active' : 'ΓåÆ adverscan.yaml configured'}
                </div>
            </div>
        </div>
    );
}

// ΓöÇΓöÇ FEATURES SECTION ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export default function FeaturesSection() {
    const sectionRef = useRef(null);

    useEffect(() => {
        const ctx = gsap.context(() => {
            gsap.from('.feature-card', {
                y: 50,
                opacity: 0,
                duration: 0.8,
                stagger: 0.15,
                ease: 'power3.out',
                scrollTrigger: {
                    trigger: sectionRef.current,
                    start: 'top 75%',
                },
            });
        }, sectionRef);
        return () => ctx.revert();
    }, []);

    return (
        <section id="features" ref={sectionRef} className="py-28 px-6 md:px-16" style={{ maxWidth: '1100px', margin: '0 auto' }}>
            <p className="section-tag mb-4">04 / Interactive Feature Artifacts</p>
            <h2 className="font-sans font-extrabold mb-4" style={{ fontSize: 'clamp(1.8rem, 4vw, 3rem)', color: 'var(--ghost)', letterSpacing: '-0.03em' }}>
                Core <span style={{ color: 'var(--plasma)' }}>feature set</span>
            </h2>
            <p className="mb-14 max-w-lg" style={{ color: 'rgba(240,239,244,0.5)', fontSize: '1rem', lineHeight: 1.8 }}>
                Each card is a functional software micro-UI ΓÇö not static marketing.
            </p>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
                <div className="feature-card"><DiagnosticShuffler /></div>
                <div className="feature-card"><TelemetryTypewriter /></div>
                <div className="feature-card"><CursorScheduler /></div>
            </div>
        </section>
    );
}

import React, { useRef, useEffect, useState } from "react";

const vsSource = `#version 300 es
in vec2 a_position;
void main() {
  gl_Position = vec4(a_position, 0.0, 1.0);
}
`;

const fsSource = `#version 300 es
precision highp float;

uniform vec2  u_resolution;
uniform float u_time;
uniform vec2  u_mouse;
uniform float u_cameraSpeed;
uniform float u_tileSize;
uniform float u_unionK;
uniform int   u_maxSteps;
uniform float u_maxDist;
uniform float u_surfDist;

out vec4 fragColor;

float sdBox(vec3 p, vec3 b) {
  vec3 q = abs(p) - b;
  return length(max(q, 0.0)) + min(max(q.x, max(q.y, q.z)), 0.0);
}

float opSmoothUnion(float d1, float d2, float k) {
  float h = clamp(0.5 + 0.5*(d2 - d1)/k, 0.0, 1.0);
  return mix(d2, d1, h) - k*h*(1.0 - h);
}

float getDist(vec3 p) {
  vec2 id = floor(p.xz / u_tileSize);
  p.xz = mod(p.xz, u_tileSize) - u_tileSize*0.5;

  float n = fract(sin(dot(id, vec2(12.9898,78.233))) * 43758.5453);
  float h = 1.0 + n * 4.0;
  float b = sdBox(p - vec3(0.0, h - 1.0, 0.0),
                  vec3(0.4, h, 0.4));

  if (n > 0.8) {
    float s = length(p - vec3(0.0, h*2.0, 0.0)) - 0.5;
    b = opSmoothUnion(b, s, u_unionK);
  }

  float ground = p.y + 1.0;
  return min(b, ground);
}

float rayMarch(vec3 ro, vec3 rd) {
  float dist = 0.0;
  for (int i = 0; i < u_maxSteps; i++) {
    vec3 pos = ro + rd * dist;
    float dS = getDist(pos);
    dist += dS;
    if (dist > u_maxDist || abs(dS) < u_surfDist) break;
  }
  return dist;
}

vec3 palette(float t) {
  vec3 a = vec3(0.02, 0.08, 0.15); 
  vec3 b = vec3(0.96, 0.62, 0.04); 
  vec3 c = vec3(1.0, 0.7, 0.4);
  vec3 d = vec3(0.0, 0.15, 0.20);
  return a + b * cos(6.28318 * (c*t + d));
}

void main() {
  vec2 uv = (gl_FragCoord.xy * 2.0 - u_resolution.xy) / u_resolution.y;

  vec3 ro = vec3(0.0, 0.0, u_time * u_cameraSpeed);
  vec3 rd = normalize(vec3(uv, 1.0));

  float mx = (u_mouse.x / u_resolution.x - 0.5) * 3.14;
  float my = (u_mouse.y / u_resolution.y - 0.5) * 1.5;
  mat3 rotX = mat3(1, 0, 0, 0, cos(my), -sin(my), 0, sin(my), cos(my));
  mat3 rotY = mat3(cos(mx), 0, sin(mx), 0, 1, 0, -sin(mx), 0, cos(mx));
  rd = rotY * rotX * rd;

  float dist = rayMarch(ro, rd);
  vec3 col = vec3(0.0);

  if (dist < u_maxDist) {
    vec3 p = ro + rd * dist;
    float idSeed = floor(p.xz / u_tileSize).x * 157.0
                 + floor(p.xz / u_tileSize).y * 311.0;
    float n = fract(sin(idSeed) * 43758.5453);

    float lines = abs(fract(p.y * 2.0) - 0.5);
    float glow  = pow(0.01 / lines, 1.5);
    
    vec3 amberHotspot = vec3(0.96, 0.62, 0.04);
    col += palette(n + u_time * 0.1) * glow * 1.5;
    
    float pulse = sin(u_time * 2.0 + p.y * 5.0) * 0.5 + 0.5;
    col += amberHotspot * pulse * 0.1 * step(0.8, n);
  }

  vec3 fogCol = vec3(0.027, 0.078, 0.157); 
  col = mix(col, fogCol, smoothstep(0.0, u_maxDist * 0.8, dist));

  fragColor = vec4(col, 1.0);
}
`;

const NeonCrystalCity = ({
  cameraSpeed = 3,
  tileSize = 4,
  unionK = 0.5,
  maxSteps = 80,
  maxDist = 100,
  surfDist = 0.005,
  className = "",
}) => {
  const canvasRef = useRef(null);
  const frameId = useRef();
  const mouse = useRef({ x: 0, y: 0 });
  const start = useRef(Date.now());

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const gl = canvas.getContext("webgl2");
    if (!gl) return;

    const compileShader = (type, src) => {
      const sh = gl.createShader(type);
      gl.shaderSource(sh, src);
      gl.compileShader(sh);
      return sh;
    };

    const vs = compileShader(gl.VERTEX_SHADER, vsSource);
    const fs = compileShader(gl.FRAGMENT_SHADER, fsSource);
    const prog = gl.createProgram();
    gl.attachShader(prog, vs);
    gl.attachShader(prog, fs);
    gl.linkProgram(prog);

    const posLoc = gl.getAttribLocation(prog, "a_position");
    const resLoc = gl.getUniformLocation(prog, "u_resolution");
    const timeLoc = gl.getUniformLocation(prog, "u_time");
    const mouseLoc = gl.getUniformLocation(prog, "u_mouse");
    const speedLoc = gl.getUniformLocation(prog, "u_cameraSpeed");
    const tileLoc = gl.getUniformLocation(prog, "u_tileSize");
    const unionLoc = gl.getUniformLocation(prog, "u_unionK");
    const stepsLoc = gl.getUniformLocation(prog, "u_maxSteps");
    const maxLoc = gl.getUniformLocation(prog, "u_maxDist");
    const surfLoc = gl.getUniformLocation(prog, "u_surfDist");

    const quadBuf = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, quadBuf);
    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1, 1, -1, -1, 1, 1, 1, -1]), gl.STATIC_DRAW);

    const onMouse = (e) => {
      mouse.current.x = e.clientX;
      mouse.current.y = e.clientY;
    };
    window.addEventListener("mousemove", onMouse);

    const resize = () => {
      const dpr = window.devicePixelRatio || 1;
      canvas.width = canvas.clientWidth * dpr;
      canvas.height = canvas.clientHeight * dpr;
      gl.viewport(0, 0, canvas.width, canvas.height);
    };
    window.addEventListener("resize", resize);
    resize();

    const render = () => {
      gl.clear(gl.COLOR_BUFFER_BIT);
      gl.useProgram(prog);
      gl.enableVertexAttribArray(posLoc);
      gl.bindBuffer(gl.ARRAY_BUFFER, quadBuf);
      gl.vertexAttribPointer(posLoc, 2, gl.FLOAT, false, 0, 0);

      const now = (Date.now() - start.current) * 0.001;
      gl.uniform2f(resLoc, canvas.width, canvas.height);
      gl.uniform1f(timeLoc, now);
      gl.uniform2f(mouseLoc, mouse.current.x, mouse.current.y);
      gl.uniform1f(speedLoc, cameraSpeed);
      gl.uniform1f(tileLoc, tileSize);
      gl.uniform1f(unionLoc, unionK);
      gl.uniform1i(stepsLoc, maxSteps);
      gl.uniform1f(maxLoc, maxDist);
      gl.uniform1f(surfLoc, surfDist);

      gl.drawArrays(gl.TRIANGLE_STRIP, 0, 4);
      frameId.current = requestAnimationFrame(render);
    };
    frameId.current = requestAnimationFrame(render);

    return () => {
      cancelAnimationFrame(frameId.current);
      window.removeEventListener("resize", resize);
      window.removeEventListener("mousemove", onMouse);
    };
  }, [cameraSpeed, tileSize, unionK, maxSteps, maxDist, surfDist]);

  return (
    <div className={`relative w-full h-full overflow-hidden ${className}`}>
      <canvas ref={canvasRef} className="block w-full h-full" />
    </div>
  );
};

export default NeonCrystalCity;

import React, { useEffect, useRef, useState } from 'react';

// Particle canvas ΓÇö native replacement for FloatingParticlesBackground (Framer)
export default function ParticleCanvas({ className = '', opacity = 0.4 }) {
    const canvasRef = useRef(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        let animId;
        let particles = [];

        const resize = () => {
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
        };

        const createParticles = () => {
            particles = [];
            const count = Math.floor((canvas.width * canvas.height) / 12000);
            for (let i = 0; i < count; i++) {
                particles.push({
                    x: Math.random() * canvas.width,
                    y: Math.random() * canvas.height,
                    vx: (Math.random() - 0.5) * 0.4,
                    vy: (Math.random() - 0.5) * 0.4,
                    r: Math.random() * 1.5 + 0.5,
                    alpha: Math.random() * 0.5 + 0.2,
                });
            }
        };

        const draw = () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Draw connections
            for (let i = 0; i < particles.length; i++) {
                for (let j = i + 1; j < particles.length; j++) {
                    const dx = particles[i].x - particles[j].x;
                    const dy = particles[i].y - particles[j].y;
                    const dist = Math.sqrt(dx * dx + dy * dy);
                    if (dist < 120) {
                        ctx.beginPath();
                        ctx.strokeStyle = `rgba(123, 97, 255, ${0.15 * (1 - dist / 120)})`;
                        ctx.lineWidth = 0.5;
                        ctx.moveTo(particles[i].x, particles[i].y);
                        ctx.lineTo(particles[j].x, particles[j].y);
                        ctx.stroke();
                    }
                }
            }

            // Draw particles
            particles.forEach(p => {
                p.x += p.vx;
                p.y += p.vy;
                if (p.x < 0) p.x = canvas.width;
                if (p.x > canvas.width) p.x = 0;
                if (p.y < 0) p.y = canvas.height;
                if (p.y > canvas.height) p.y = 0;

                ctx.beginPath();
                ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
                ctx.fillStyle = `rgba(123, 97, 255, ${p.alpha})`;
                ctx.fill();
            });

            animId = requestAnimationFrame(draw);
        };

        resize();
        createParticles();
        draw();

        const ro = new ResizeObserver(() => {
            resize();
            createParticles();
        });
        ro.observe(canvas);

        return () => {
            cancelAnimationFrame(animId);
            ro.disconnect();
        };
    }, []);

    return (
        <canvas
            ref={canvasRef}
            className={className}
            style={{ display: 'block', width: '100%', height: '100%', opacity }}
        />
    );
}

import React, { useEffect, useRef } from 'react';
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

// Canvas animation 1 ΓÇö slowly rotating double helix / concentric circles
function ConcentricCanvas() {
    const canvasRef = useRef(null);
    useEffect(() => {
        const c = canvasRef.current;
        const ctx = c.getContext('2d');
        let t = 0, id;
        const draw = () => {
            c.width = c.offsetWidth; c.height = c.offsetHeight;
            ctx.clearRect(0, 0, c.width, c.height);
            const cx = c.width / 2, cy = c.height / 2;
            for (let r = 20; r < 120; r += 22) {
                ctx.beginPath();
                ctx.arc(cx, cy, r, 0, Math.PI * 2);
                ctx.strokeStyle = `rgba(123,97,255,${0.5 - r / 300})`;
                ctx.lineWidth = 1;
                ctx.stroke();
                // Rotating dots on circles
                for (let i = 0; i < 6; i++) {
                    const angle = (i / 6) * Math.PI * 2 + t * (r % 2 === 0 ? 1 : -1);
                    ctx.beginPath();
                    ctx.arc(cx + Math.cos(angle) * r, cy + Math.sin(angle) * r, 2.5, 0, Math.PI * 2);
                    ctx.fillStyle = 'rgba(123,97,255,0.8)';
                    ctx.fill();
                }
            }
            t += 0.01;
            id = requestAnimationFrame(draw);
        };
        draw();
        return () => cancelAnimationFrame(id);
    }, []);
    return <canvas ref={canvasRef} style={{ width: '100%', height: '160px', display: 'block' }} />;
}

// Canvas animation 2 ΓÇö scanning horizontal laser line across dot grid
function ScannerCanvas() {
    const canvasRef = useRef(null);
    useEffect(() => {
        const c = canvasRef.current;
        const ctx = c.getContext('2d');
        let scanY = 0, id;
        const draw = () => {
            c.width = c.offsetWidth; c.height = c.offsetHeight;
            ctx.clearRect(0, 0, c.width, c.height);
            const cols = 10, rows = 5;
            const gw = c.width / cols, gh = c.height / rows;
            for (let r = 0; r < rows; r++) {
                for (let col = 0; col < cols; col++) {
                    const x = col * gw + gw / 2;
                    const y = r * gh + gh / 2;
                    const dist = Math.abs(y - scanY);
                    const alpha = dist < 20 ? 0.9 - dist / 20 * 0.6 : 0.15;
                    ctx.beginPath();
                    ctx.arc(x, y, 2, 0, Math.PI * 2);
                    ctx.fillStyle = `rgba(0,255,150,${alpha})`;
                    ctx.fill();
                }
            }
            // Laser line
            const grad = ctx.createLinearGradient(0, 0, c.width, 0);
            grad.addColorStop(0, 'transparent');
            grad.addColorStop(0.5, 'rgba(0,255,150,0.8)');
            grad.addColorStop(1, 'transparent');
            ctx.fillStyle = grad;
            ctx.fillRect(0, scanY - 1, c.width, 2);
            scanY = (scanY + 1.5) % c.height;
            id = requestAnimationFrame(draw);
        };
        draw();
        return () => cancelAnimationFrame(id);
    }, []);
    return <canvas ref={canvasRef} style={{ width: '100%', height: '160px', display: 'block' }} />;
}

// SVG animation 3 ΓÇö EKG pulsing waveform via stroke-dashoffset
function WaveformSVG() {
    return (
        <div style={{ width: '100%', height: '160px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
