                />
                <style>{`
          @keyframes ekgPulse {
            0% { stroke-dashoffset: 600; opacity: 0.3; }
            40% { opacity: 1; }
            100% { stroke-dashoffset: -600; opacity: 0.3; }
          }
        `}</style>
            </svg>
        </div>
    );
}

