        { id: 2, label: 'CountryWatcher', val: 'ACTIVE v1.0' },
        { id: 3, label: 'Privacy Protocol', val: 'FULLY SOVEREIGN' }
    ]);

    useEffect(() => {
        const timer = setInterval(() => {
            setItems(prev => {
                const next = [...prev];
                next.unshift(next.pop());
                return next;
            });
        }, 3000);
        return () => clearInterval(timer);
    }, []);

    return (
        <div className="relative h-48 w-full flex flex-col items-center justify-center perspective-1000">
            {items.map((item, idx) => (
                <div
                    key={item.id}
                    className="absolute w-full max-w-[280px] bg-[#2A2A35] border border-[#FAF8F5]/10 p-4 rounded-2xl transition-all duration-700 ease-[cubic-bezier(0.34,1.56,0.64,1)]"
                    style={{
                        transform: `translateY(${(idx - 1) * 30}px) scale(${1 - Math.abs(idx - 1) * 0.1})`,
                        opacity: idx === 1 ? 1 : 0.4,
                        zIndex: idx === 1 ? 10 : 0
                    }}
                >
                    <div className="flex justify-between items-center">
                        <span className="text-[10px] font-mono text-[#FAF8F5]/40 uppercase tracking-widest">{item.label}</span>
                        <Activity size={12} className="text-[#F59E0B]" />
                    </div>
                    <div className="mt-1 font-mono text-sm text-[#F59E0B]">{item.val}</div>
                </div>
            ))}
        </div>
    );
};

const TelemetryTypewriter = () => {
    const text = "ANALYZING ILI CLUSTERS... DBSCAN PARAMETERS OPTIMIZED... HOTSPOT DETECTED AT 30.27┬░N 120.15┬░E... CONFIDENCE: 0.81";
    const [display, setDisplay] = useState("");
    const [index, setIndex] = useState(0);

    useEffect(() => {
        if (index < text.length) {
            const timer = setTimeout(() => {
                setDisplay(prev => prev + text[index]);
                setIndex(index + 1);
            }, 50);
            return () => clearTimeout(timer);
        } else {
            setTimeout(() => {
                setDisplay("");
                setIndex(0);
            }, 3000);
        }
    }, [index]);

    return (
        <div className="bg-[#0D0D12] p-4 rounded-2xl border border-[#FAF8F5]/5 h-32 font-mono text-[10px] relative overflow-hidden">
            <div className="flex items-center gap-2 mb-2">
                <div className="w-2 h-2 bg-[#F59E0B] rounded-full animate-pulse" />
                <span className="text-[#FAF8F5]/40 uppercase tracking-widest">Live Telemetry Feed</span>
            </div>
            <div className="text-[#F59E0B]/80 leading-relaxed uppercase">
                {display}<span className="inline-block w-1 h-3 bg-[#F59E0B] ml-1 animate-pulse" />
            </div>
        </div>
    );
};

const ProtocolScheduler = () => {
    const [active, setActive] = useState(0);
    const days = ['S', 'M', 'T', 'W', 'T', 'F', 'S'];

    useEffect(() => {
        const timer = setInterval(() => {
            setActive(prev => (prev + 1) % 7);
        }, 1500);
        return () => clearInterval(timer);
    }, []);

    return (
        <div className="bg-[#2A2A35]/50 p-4 rounded-2xl border border-[#FAF8F5]/5 w-full">
            <div className="flex justify-between mb-4">
                {days.map((d, i) => (
                    <div
                        key={i}
                        className={cn(
                            "w-8 h-8 rounded-lg flex items-center justify-center font-mono text-xs transition-colors duration-500",
                            active === i ? "bg-[#F59E0B] text-[#0D0D12] shadow-[0_0_15px_rgba(245,158,11,0.3)]" : "bg-[#0D0D12] text-[#FAF8F5]/30"
                        )}
                    >
                        {d}
                    </div>
                ))}
            </div>
            <div className="flex items-center justify-between">
                <div className="flex -space-x-2">
                    {[1, 2, 3].map(i => <div key={i} className="w-6 h-6 rounded-full bg-[#FAF8F5]/10 border border-[#0D0D12]" />)}
                </div>
                <button className="px-3 py-1 bg-[#F59E0B]/10 border border-[#F59E0B]/20 rounded-md text-[10px] text-[#F59E0B] font-mono uppercase">
                    Finalizing Protocol
                </button>
            </div>
        </div>
    );
};

